import{_ as t,a}from"./chunks/填写github渠道配置.B-S0-llS.js";import{_ as n,o as s,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Add a GitHub Releases Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/github-releases.md","filePath":"en/upload/github-releases.md","lastUpdated":1781962217000}'),r={name:"en/upload/github-releases.md"};function d(l,e,c,h,p,u){return s(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="add-a-github-releases-channel" tabindex="-1">Add a GitHub Releases Channel <a class="header-anchor" href="#add-a-github-releases-channel" aria-label="Permalink to &quot;Add a GitHub Releases Channel&quot;">​</a></h1><h2 id="what-you-need-before-you-start" tabindex="-1">What You Need Before You Start <a class="header-anchor" href="#what-you-need-before-you-start" aria-label="Permalink to &quot;What You Need Before You Start&quot;">​</a></h2><p>You only need three things:</p><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>GitHub account</td><td>Used to generate an access token and own the repository.</td></tr><tr><td>GitHub Access Token</td><td>Used by ImgBed to access the GitHub API, create releases, and upload files.</td></tr><tr><td>Repository name</td><td>You can enter only the repository name, for example <code>image</code>.</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-sign-in-to-github-and-create-an-access-token" tabindex="-1">Step 1: Sign in to GitHub and Create an Access Token <a class="header-anchor" href="#step-1-sign-in-to-github-and-create-an-access-token" aria-label="Permalink to &quot;Step 1: Sign in to GitHub and Create an Access Token&quot;">​</a></h3><ol><li>Sign in to GitHub.</li><li>Click your avatar in the upper-right corner and open <code>Settings</code>.</li><li>Open <code>Developer settings</code> from the left sidebar.</li><li>Open <code>Personal access tokens</code>.</li><li>Open <code>Tokens (classic)</code>.</li><li>Click <code>Generate new token (classic)</code>.</li><li>Give the token a recognizable name.</li><li>Choose an expiration date based on your own maintenance preference.</li><li>Select the <code>repo</code> and <code>workflow</code> scopes.</li><li>Copy and save the token immediately after it is created.</li></ol><p><img src="'+t+'" alt="Add GitHub permissions" loading="lazy"></p><h2 id="step-2-fill-in-the-github-releases-channel-in-imgbed" tabindex="-1">Step 2: Fill in the GitHub Releases Channel in ImgBed <a class="header-anchor" href="#step-2-fill-in-the-github-releases-channel-in-imgbed" aria-label="Permalink to &quot;Step 2: Fill in the GitHub Releases Channel in ImgBed&quot;">​</a></h2><p>After selecting <code>GitHub Releases</code> in Upload Settings, fill in the fields as follows:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>What to Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>A name you choose, such as <code>GitHubPrimary</code>.</td></tr><tr><td>Access Token</td><td>The GitHub Personal Access Token you just created.</td></tr><tr><td>Repository name</td><td>Either a short repo name such as <code>image</code>, or a full path such as <code>username/image</code>.</td></tr><tr><td>Private repository</td><td>Turn on or off based on your needs.</td></tr><tr><td>Remark</td><td>Optional, for example <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+a+`" alt="Fill in the GitHub channel configuration" loading="lazy"></p><h2 id="step-3-save-the-channel" tabindex="-1">Step 3: Save the Channel <a class="header-anchor" href="#step-3-save-the-channel" aria-label="Permalink to &quot;Step 3: Save the Channel&quot;">​</a></h2><p>After filling in the fields, click Save.</p><p>The system will handle these details:</p><table tabindex="0"><thead><tr><th>System Behavior</th><th>Description</th></tr></thead><tbody><tr><td>Short repository name</td><td>ImgBed identifies the current GitHub account and expands the value into a full repository path.</td></tr><tr><td>Full repository path</td><td>ImgBed uses the <code>username/repository</code> path exactly as entered.</td></tr><tr><td>Repository check</td><td>If you use the current personal account path, ImgBed automatically creates the repository when it does not exist. If you enter a full path manually, ImgBed uses that path directly.</td></tr><tr><td>Public/private state</td><td>Repository visibility is synchronized according to the current switch.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><p>GitHub Releases works like this:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sign in to GitHub</span></span>
<span class="line"><span>-&gt; Create an Access Token</span></span>
<span class="line"><span>-&gt; Return to ImgBed and enter the token and repository name</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; If only a repo name is entered, ImgBed adds the current username automatically</span></span>
<span class="line"><span>-&gt; If username/repo is entered, ImgBed uses it as-is</span></span>
<span class="line"><span>-&gt; Upload a test image</span></span></code></pre></div>`,19)])])}const y=n(r,[["render",d]]);export{g as __pageData,y as default};
